from typing import List

class Solution:
    def countKDifference(self, nums: List[int], k: int) -> int:
        count_map = {}
        total_count = 0
        for num in nums:
            if num - k in count_map:
                total_count += count_map[num - k]
            if num + k in count_map:
                total_count += count_map[num + k]
            count_map[num] = count_map.get(num, 0) + 1
        return total_count

